class DSU {
    constructor(n) {
        this.parent = Array(n).fill(0).map((_, i) => i);
        // dist[i]: parity of path weight from i to parent[i]
        this.dist = Array(n).fill(0); 
    }

    // Returns [root, parity_distance_from_i_to_root]
    find(i) {
        if (this.parent[i] === i) {
            return [i, 0];
        }

        // Path compression
        const [root, root_dist] = this.find(this.parent[i]);

        // Update distance: dist[i] (i -> parent[i]) XOR root_dist (parent[i] -> root)
        // New distance i -> root is (i -> parent[i]) + (parent[i] -> root) (mod 2)
        this.dist[i] = this.dist[i] ^ root_dist;
        this.parent[i] = root;

        return [root, this.dist[i]];
    }

    // Attempts to unite u and v using edge weight w.
    // Returns true if the edge was added (or was consistent if already connected), false if it created an odd cycle.
    union(u, v, w) {
        // Find root and distances
        const [rootU, distU] = this.find(u);
        const [rootV, distV] = this.find(v);

        if (rootU === rootV) {
            // Cycle check
            // Path u -> rootU has parity distU
            // Path v -> rootV has parity distV
            // Cycle weight = (u -> rootU) + (v -> rootV) + (u --w--> v) + (rootV -> u) 
            // Wait, the cycle is u --w--> v --(path)--> rootV(=rootU) --(path)--> u
            // Cycle weight = w + (u -> v path parity)
            // Parity of path u -> v is distU XOR distV.
            // If we add w, total cycle weight = distU ^ distV ^ w.

            if ((distU ^ distV ^ w) === 0) {
                // Even cycle weight. Accept edge.
                return true;
            } else {
                // Odd cycle weight. Reject edge.
                return false;
            }
        } else {
            // Merge components. We merge V into U (arbitrary choice for simplicity).
            this.parent[rootV] = rootU;

            // We need to set dist[rootV] = parity(rootV -> rootU)
            // Path: rootV -> v --w--> u -> rootU
            // Parity(rootV -> v) = distV (since distV = parity(v -> rootV))
            // Parity(u -> rootU) = distU
            // Parity(rootV -> rootU) = distV ^ w ^ distU
            this.dist[rootV] = distV ^ w ^ distU;

            return true;
        }
    }
}

function solve(n, edges) {
    const dsu = new DSU(n);
    let addedEdgesCount = 0;

    for (const edge of edges) {
        const u = edge[0];
        const v = edge[1];
        const w = edge[2];

        // We call union. It returns true if the edge is accepted based on cycle constraints, 
        // or false if it creates an odd cycle.
        if (dsu.union(u, v, w)) {
            addedEdgesCount++;
        }
    }

    return addedEdgesCount;
}
